namespace sv_9455470e46754686b6ce484736979153.Services;

/// <summary>
/// Scoped service that holds the current warehouse selection and alert state
/// for a single user circuit. Provides change notification events so unrelated
/// components can stay synchronized.
/// </summary>
public sealed class WarehouseStateService : IDisposable
{
    private string _currentWarehouseId = "WH-001";
    private int _lowStockCount;

    public string CurrentWarehouseId
    {
        get => _currentWarehouseId;
        set
        {
            if (_currentWarehouseId == value) return;
            _currentWarehouseId = value;
            NotifyStateChanged();
        }
    }

    public int LowStockCount
    {
        get => _lowStockCount;
        set
        {
            if (_lowStockCount == value) return;
            _lowStockCount = value;
            NotifyStateChanged();
        }
    }

    /// <summary>
    /// Raised whenever warehouse selection or alert data changes.
    /// Components subscribe to this to re-render.
    /// </summary>
    public event Action? OnChange;

    private void NotifyStateChanged() => OnChange?.Invoke();

    public void Dispose()
    {
        // Clear all subscribers to prevent leaks if the circuit outlives components.
        OnChange = null;
    }
}

