/// Simulates a database query that returns the count of items below minimum stock levels.
/// Registered as scoped so each circuit gets its own instance (though the logic is stateless).
/// </summary>
public sealed class InventoryAlertService
{
    private readonly Random _random = new();

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate async DB call with a random result between 0 and 15.
        int count = _random.Next(0, 16);
        return Task.FromResult(count);
    }
}

