@using sv_9455470e46754686b6ce484736979153.Services
@rendermode InteractiveServer
@inject WarehouseStateService State
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Warehouse Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">Current Warehouse</h5>
        <p class="card-text fs-5">
            <strong>@GetWarehouseName(State.CurrentWarehouseId)</strong>
            <span class="text-muted">(@State.CurrentWarehouseId)</span>
        </p>
    </div>
</div>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">
            Low-Stock Alerts
            @if (State.LowStockCount > 0)
            {
                <span class="badge bg-danger ms-2">@State.LowStockCount items</span>
            }
            else
            {
                <span class="badge bg-success ms-2">All stocked</span>
            }
        </h5>
        <p class="card-text text-muted">
            Polling every 10 seconds. Last check: @_lastCheck?.ToString("HH:mm:ss")
        </p>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;
    private DateTime? _lastCheck;

    protected override void OnInitialized()
    {
        State.OnChange += OnStateChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await PollNow();
            StartPolling();
        }
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _ = PollLoop(_cts.Token);
    }

    private async Task PollLoop(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(10), ct).ConfigureAwait(false);
            if (ct.IsCancellationRequested) break;
            await InvokeAsync(PollNow);
        }
    }

    private async Task PollNow()
    {
        var count = await AlertService.GetLowStockCountAsync(State.CurrentWarehouseId);
        _lastCheck = DateTime.Now;
        // Setting this property fires OnChange, which notifies ALL subscribers
        // (AlertBadge in sidebar, this page, any future components).
        State.LowStockCount = count;
    }

    private void OnStateChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private static string GetWarehouseName(string id)
    {
        return WarehouseDirectory.Warehouses
            .FirstOrDefault(w => w.Id == id).Name ?? id;
    }

    public void Dispose()
    {
        State.OnChange -= OnStateChanged;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

